function min_trips(boxes, portsCount, maxBoxes, maxWeight) {
    let trips = 0, idx = 0, n = boxes.length;
    while (idx < n) {
        let curr_limit = maxWeight, prev_port = 0;
        for (let count = 0; count < maxBoxes && idx < n; ++idx) {
            if (boxes[idx][1] <= curr_limit) {
                if (prev_port !== boxes[idx][0]) {
                    prev_port = boxes[idx][0];
                    trips += 1;
                }
                curr_limit -= boxes[idx][1];
                count += 1;
            }
        }
        trips += 1;
    }
    return trips;
}
```

    The algorithm works as follows:
1. Initialize `trips` to store minimum trips, `idx` to traverse boxes, length `n` of boxes.
2. Create a while loop, while `idx` is less than `n`, repeating steps 3-9.
3. Set `curr_limit` as the maximum weight to keep track of remaining weight allowed, and set `prev_port` to 0 as the initial previous port.
4. Run a for loop upto `maxBoxes` and `idx` less than `n`.
5. Check if the `weights_i` from boxes less than or equal to the `curr_limit`, if yes, go to step 6, else break.
6. If `ports_i` is not equal to the `prev_port`, update the `prev_port` with the value of `ports_i` and increment `trips`.
7. Decrement the `curr_limit` by the value of `weights_i`.
8. Increment the counter for the inner for loop (for the number of boxes).
9. Increment the `trips`.
10. Return the value of `trips`.

